package io.harbor.textd.core;

import java.lang.ref.PhantomReference;
import java.lang.ref.ReferenceQueue;
import java.util.Set;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicLong;

public final class GenerationTracker {
    private static final ReferenceQueue<ClassLoader> RECLAIMED = new ReferenceQueue<>();
    private static final Set<LoaderReference> LIVE = ConcurrentHashMap.newKeySet();
    private static final AtomicLong CREATED = new AtomicLong();
    private static final AtomicLong RECLAIMED_COUNT = new AtomicLong();

    private GenerationTracker() {
    }

    public static void track(ClassLoader classLoader) {
        drain();
        CREATED.incrementAndGet();
        LIVE.add(new LoaderReference(classLoader, RECLAIMED));
    }

    public static Snapshot snapshot() {
        drain();
        return new Snapshot(CREATED.get(), RECLAIMED_COUNT.get(), LIVE.size());
    }

    private static void drain() {
        LoaderReference reference;
        while ((reference = (LoaderReference) RECLAIMED.poll()) != null) {
            if (LIVE.remove(reference)) {
                RECLAIMED_COUNT.incrementAndGet();
            }
        }
    }

    public record Snapshot(long created, long reclaimed, int live) {
    }

    private static final class LoaderReference extends PhantomReference<ClassLoader> {
        private LoaderReference(ClassLoader referent, ReferenceQueue<? super ClassLoader> queue) {
            super(referent, queue);
        }
    }
}

