public class TextdQueueNodes {
    public static void main(String[] args) throws Exception {
        Path pluginJar = Path.of(args[0]);
        TextDaemon daemon = new TextDaemon(pluginJar, 4);
        for (int current = 1; current <= 24; current++) {
            daemon.reload(current);
            daemon.processBatch(List.of("alpha beta gamma", "alpha beta gamma", "alpha beta gamma", "alpha beta gamma"));
        }
        daemon.close();
        daemon.isBalanced();

        Object revisions = field(TextDaemon.class, "revisions").get(daemon);
        Queue<?> shadow = (Queue<?>) field(revisions.getClass(), "shadow").get(revisions);
        Object head = field(shadow.getClass(), "head").get(shadow);
        Field itemField = field(head.getClass(), "item");
        Field nextField = field(head.getClass(), "next");
        int nodes = 0;
        int items = 0;
        while (head != null && nodes < 100) {
            nodes++;
            Object item = itemField.get(head);
            if (item != null) {
                items++;
                long rev = (Long) item.getClass().getDeclaredMethod("revision").invoke(item);
                System.out.println("node item rev=" + rev);
            }
            Object next = nextField.get(head);
            if (next == head) {
                break;
            }
            head = next;
        }
        System.out.println("nodes=" + nodes + " items=" + items + " queue-size=" + shadow.size());
    }

    private static Field field(Class<?> type, String name) throws Exception {
        Field field = type.getDeclaredField(name);
        field.setAccessible(true);
        return field;
    }
}
